INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Cuarto Grado', 'Productividad y Desarrollo', '1. Utiliza información, de diferentes fuentes, que le facilita encontrar respuestas a su curiosidad natural y a la comprensión de su entorno.', ARRAY['1.1. Ejecuta diferentes formas de recopilar información, a partir de las fuentes que tiene a su alcance.', '1.2. Registra aspectos, en forma oral y escrita, derivados de la observación y de la información.', '1.3. Elabora informes escritos o representaciones de la información recopilada.', '1.4. Participa activa y respetuosamente, en el equipo de trabajo.']),
('Cuarto Grado', 'Productividad y Desarrollo', '2. Utiliza la comunicación como elemento facilitador del logro de calidad en sus producciones personales.', ARRAY['2.1. Explica la importancia de respetar normas y aplicarlas, así como de tener presente parámetros para el logro de resultados con calidad.', '2.2. Participa en actividades de retroalimentación en función de mejorar procesos y resultados.', '2.3. Explica cuando menos tres formas de mejorar la relación cliente-proveedor.', '2.4. Valora la comunicación como un elemento clave para obtener calidad en distintas creaciones personales y colectivas.']),
('Cuarto Grado', 'Productividad y Desarrollo', '3. Identifica la presencia de tecnología como alternativa innovadora para la solución de problemas de su entorno inmediato.', ARRAY['3.1. Utiliza los recursos a su alcance para la satisfacción de necesidades que se le presentan en su vida cotidiana.', '3.2. Utiliza los elementos tecnológicos materiales e intelectuales propios de la familia y comunidad en acciones de la vida cotidiana.', '3.3. Promueve la divulgación de información de peligros en el uso de herramientas y máquinas.', '3.4. Propone opciones que permiten el uso de tecnología en la solución de problemas.']),
('Cuarto Grado', 'Productividad y Desarrollo', '4. Relaciona las actividades productivas y de servicio con el desarrollo de su comunidad.', ARRAY['4.1. Utiliza los recursos a su alcance para satisfacer sus necesidades y superar las dificultades que se le presentan en su vida cotidiana.', '4.2. Diferencia entre demanda y oferta; entre competencia y red de apoyo.', '4.3. Describe cómo las actividades económicas se relacionan con la vida de las personas de la comunidad.', '4.4. Diferencia los productos y servicios que se generan en su comunidad de los que provienen de otras.']),
('Cuarto Grado', 'Productividad y Desarrollo', '5. Participa en actividades orientadas a la búsqueda de soluciones a problemas de su entorno inmediato.', ARRAY['5.1. Propone diversas opciones de solución a los problemas de contaminación en el centro educativo y en su entorno.', '5.2. Explica la importancia del medio ambiente, su protección, rescate y conservación.', '5.3. Participa en actividades de protección, conservación y rescate de los recursos naturales y culturales de su entorno.']);
